import { useEffect, useState } from "react";
import { getCart } from "../api/api";

function Cart() {
  const [cart, setCart] = useState(null);

  useEffect(() => {
    loadCart();
  }, []);

  async function loadCart() {
    try {
      const data = await getCart(1);
      setCart(data);
    } catch (error) {
      console.error("Fel vid hämtning av varukorg:", error);
    }
  }

  if (!cart) return <p>Laddar...</p>;

  return (
    <div style={{ padding: "30px" }}>
      <h1>Varukorg</h1>

      {cart.items.length === 0 ? (
        <p>Varukorgen är tom</p>
      ) : (
        cart.items.map((item, index) => (
          <div
            key={index}
            style={{
              border: "1px solid #ccc",
              padding: "15px",
              marginBottom: "15px",
              borderRadius: "8px",
              background: "white"
            }}
          >
            <h3>{item.name}</h3>
            <p>Pris per styck: {item.price} kr</p>
            <p>Antal: {item.amount}</p>
            <p>Summa: {item.price * item.amount} kr</p>
          </div>
        ))
      )}

      <h2>Total: {cart.totalPrice} kr</h2>
    </div>
  );
}

export default Cart;
